import socket

def handle_status_query(data, addr):
    # Simulate a response with a full player list and game state
    players = ["Player1", "Player2", "Player3"]
    game_state = {"map": "Desert", "mode": "Capture the Flag"}
    response = f"Players: {', '.join(players)} | Game State: {game_state}"
    return response.encode(), addr

def main():
    server_address = ('0.0.0.0', 12345)
    buffer_size = 4096
    
    # Create a UDP socket
    sock = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)
    
    try:
        # Bind the socket to the address and port
        sock.bind(server_address)
        print(f"Server started on {server_address[0]}:{server_address[1]}")
        
        while True:
            # Receive data from a client
            data, addr = sock.recvfrom(buffer_size)
            
            if not data:
                continue
            
            query = data.decode()
            if query == "status":
                response, addr = handle_status_query(data, addr)
                sock.sendto(response, addr)
    
    except KeyboardInterrupt:
        print("Server shutting down.")
    finally:
        sock.close()

if __name__ == "__main__":
    main()